export const 鎮宅三光 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：桿＋圈杙柱二＋右圈柱六
    線(p => p.M(X(0.6), Z(1.2)).C(X(2.2), Z(1.0), X(4.2), Z(1.0), X(5.9), Z(1.15)));
    圈(6.3, 1.1);
    線(p => p.M(X(0.6), Z(2.5)).L(X(2.4), Z(2.45)));
    圈(2.2, 3.0);
    連([2.2, 3.0], [2.2, 5.2]);
    圈(2.2, 5.2);
    圈(4.6, 4.0);
    連([4.6, 4.0], [4.6, 5.3]);
    圈(4.6, 5.3);
    for (const z of [1.9, 2.9, 3.9, 4.9, 5.8])
        圈(6.6, z);
    // 爿箱層
    線(p => p.M(X(0.8), Z(6.6)).L(X(0.8), Z(9.0)));
    線(p => p.M(X(0.85), Z(6.65)).L(X(2.6), Z(6.6)).L(X(2.6), Z(8.95)));
    線(p => p.M(X(0.9), Z(7.8)).L(X(2.55), Z(7.77)), 0.32);
    線(p => p.M(X(3.2), Z(6.6)).L(X(3.2), Z(8.9)).L(X(5.0), Z(8.85))
        .L(X(5.0), Z(6.55)).L(X(3.15), Z(6.6)));
    線(p => p.M(X(3.3), Z(7.75)).L(X(4.9), Z(7.72)), 0.32);
    線(p => p.M(X(5.6), Z(6.55)).L(X(5.6), Z(8.85)), 0.36);
    // 寬桁
    線(p => p.M(X(0.9), Z(9.6)).L(X(6.6), Z(9.5)), 0.42);
    線(p => p.M(X(0.9), Z(10.4)).L(X(6.6), Z(10.3)), 0.42);
    // 心曲雙疊（必心之形——摹形從簡）
    const 心 = (z0) => {
        線(p => p.M(X(2.2), Z(z0))
            .C(X(1.8), Z(z0 + 0.6), X(2.0), Z(z0 + 1.2), X(2.7), Z(z0 + 1.3))
            .C(X(3.3), Z(z0 + 1.4), X(3.7), Z(z0 + 1.0), X(3.6), Z(z0 + 0.5)), 0.38);
        bi.dot(X(2.7), Z(z0 + 0.35), 0.26);
        bi.dot(X(3.5), Z(z0 - 0.1), 0.26);
        bi.dot(X(4.2), Z(z0 + 0.5), 0.26);
    };
    心(11.3);
    心(13.3);
    // 底目＋巳曲＋右軌
    線(p => p.M(X(0.9), Z(15.2)).L(X(0.9), Z(18.6)));
    線(p => p.M(X(3.6), Z(15.15)).L(X(3.6), Z(18.55)));
    for (const z of [15.2, 16.9, 18.6])
        線(p => p.M(X(0.9), Z(z)).L(X(3.6), Z(z - 0.05)));
    線(p => p.M(X(4.5), Z(15.4))
        .C(X(4.2), Z(16.2), X(4.4), Z(16.9), X(5.1), Z(17.0))
        .C(X(5.7), Z(17.1), X(5.9), Z(16.6), X(5.6), Z(16.3))
        .C(X(5.3), Z(16.9), X(5.4), Z(17.6), X(5.9), Z(18.1)), 0.36);
    線(p => p.M(X(6.7), Z(6.6)).L(X(6.7), Z(18.4)));
};
